mapper.select:
SELECT COUNT(*)
FROM product p
WHERE 1=1


    AND (
        p.target_customer = #{targetCustomer}
        OR p.target_customer = 'all'
    )



    AND p.product_type = #{productType}



    AND (
        p.product_name LIKE '%' || #{keyword} || '%'
        OR p.product_desc LIKE '%' || #{keyword} || '%'
    )


AND p.is_active = 'T'
